// Valida payload de entrada e decide o stop_reason correto.
//
// Payload esperado:
//   company_id      : uuid (obrigatório)
//   contact_id      : uuid (obrigatório)
//   conversation_id : uuid (opcional)
//   deal_id         : uuid (opcional)
//   event_type      : string — tipo do evento CRM
//
// event_type → stop_reason mapping:
//   deal_won              → deal_won
//   deal_lost             → deal_lost
//   deal_stage_changed    → deal_stage_changed
//   meeting_booked        → meeting_booked
//   human_took_over       → human_took_over
//   conversation_closed   → conversation_closed
//   opt_out               → opt_out
//   manual                → manual_cancel

const input = $input.first().json;

const company_id      = input.company_id      || null;
const contact_id      = input.contact_id      || null;
const conversation_id = input.conversation_id || null;
const deal_id         = input.deal_id         || null;
const event_type      = input.event_type      || 'manual';

if (!company_id || !contact_id) {
  console.log('[follow_up_rpc_error] crm_stop_cycle: company_id ou contact_id ausente');
  return [{ json: { skip: true, reason: 'missing_ids' } }];
}

const reason_map = {
  'deal_won':            'deal_won',
  'deal_lost':           'deal_lost',
  'deal_stage_changed':  'deal_stage_changed',
  'meeting_booked':      'meeting_booked',
  'human_took_over':     'human_took_over',
  'conversation_closed': 'conversation_closed',
  'opt_out':             'opt_out',
  'manual':              'manual_cancel',
  'cadence_paused':      'cadence_paused',
  'autopilot_disabled':  'autopilot_disabled'
};

const stop_reason = reason_map[event_type] || 'manual_cancel';

console.log('[follow_up_cycle_stopped]' +
  ' event_type='     + event_type +
  ' stop_reason='    + stop_reason +
  ' company_id='     + company_id +
  ' contact_id='     + contact_id +
  ' conversation_id='+ conversation_id +
  ' deal_id='        + deal_id);

return [{
  json: {
    company_id,
    contact_id,
    conversation_id,
    deal_id,
    event_type,
    stop_reason,
    skip: false
  }
}];

