// Loga resultado do stop cycle.
// was_active=false é OK — significa que não havia ciclo ativo (idempotente).
const result = $input.first().json;
const ctx    = $('validate_crm_event').first().json;

if (result && result.success) {
  if (result.was_active) {
    console.log('[follow_up_cycle_stopped]' +
      ' event='                + ctx.event_type +
      ' reason='               + ctx.stop_reason +
      ' company_id='           + ctx.company_id +
      ' contact_id='           + ctx.contact_id +
      ' cycle_id='             + result.cycle_id +
      ' cancelled_operations=' + result.cancelled_operations +
      ' cancelled_triggers='   + result.cancelled_triggers);
  } else {
    console.log('[follow_up_cycle_stopped] nenhum ciclo ativo encontrado' +
      ' event='    + ctx.event_type +
      ' company_id='+ ctx.company_id +
      ' contact_id='+ ctx.contact_id +
      ' (was_active=false — idempotente)');
  }
} else {
  console.log('[follow_up_rpc_error] stop_follow_up_cycle falhou:' + JSON.stringify(result));
}

return [{ json: {
  success:              result ? result.success              : false,
  was_active:           result ? result.was_active           : false,
  cycle_id:             result ? result.cycle_id             : null,
  cancelled_operations: result ? result.cancelled_operations : 0,
  cancelled_triggers:   result ? result.cancelled_triggers   : 0
}}];
